import itertools
class Solution:
    def minCost(self, n, cost):
        best = None
        for colors in itertools.product(range(3), repeat=n):
            ok = True
            for i in range(1, n):
                if colors[i] == colors[i - 1]:
                    ok = False
                    break
            if ok:
                for i in range(n // 2):
                    if colors[i] == colors[n - 1 - i]:
                        ok = False
                        break
            if not ok:
                continue
            total = sum(cost[i][colors[i]] for i in range(n))
            if best is None or total < best:
                best = total
        return best

