        INF = float('inf')
        dp = [[INF] * 3 for _ in range(3)]
        for c1 in range(3):
            for c2 in range(3):
                if c1 != c2:
                    dp[c1][c2] = cost[0][c1] + cost[n - 1][c2]
        half = n // 2
        for i in range(1, half):
            j = n - 1 - i
            ndp = [[INF] * 3 for _ in range(3)]
            for c1 in range(3):
                for c2 in range(3):
                    if c1 == c2:
                        continue
                    base = cost[i][c1] + cost[j][c2]
                    best_prev = INF
                    for pc1 in range(3):
                        if pc1 == c1:
                            continue
                        for pc2 in range(3):
                            if pc2 == c2:
                                continue
                            if dp[pc1][pc2] < best_prev:
                                best_prev = dp[pc1][pc2]
                    ndp[c1][c2] = base + best_prev
            dp = ndp
        ans = INF
        for c1 in range(3):
            for c2 in range(3):
                if c1 != c2 and dp[c1][c2] < ans:
                    ans = dp[c1][c2]
        return ans

