var minCost = function(n, cost) {
    const INF = Infinity;
    let dp = [[INF, INF, INF], [INF, INF, INF], [INF, INF, INF]];
    for (let c1 = 0; c1 < 3; c1++) {
        for (let c2 = 0; c2 < 3; c2++) {
            if (c1 !== c2) dp[c1][c2] = cost[0][c1] + cost[n - 1][c2];
        }
    }
    const half = Math.floor(n / 2);
    for (let i = 1; i < half; i++) {
        const j = n - 1 - i;
        const ndp = [[INF, INF, INF], [INF, INF, INF], [INF, INF, INF]];
        for (let c1 = 0; c1 < 3; c1++) {
            for (let c2 = 0; c2 < 3; c2++) {
                if (c1 === c2) continue;
                const base = cost[i][c1] + cost[j][c2];
                let bestPrev = INF;
                for (let pc1 = 0; pc1 < 3; pc1++) {
                    if (pc1 === c1) continue;
                    for (let pc2 = 0; pc2 < 3; pc2++) {
                        if (pc2 === c2) continue;
                        if (dp[pc1][pc2] < bestPrev) bestPrev = dp[pc1][pc2];
                    }
                }
                ndp[c1][c2] = base + bestPrev;
            }
        }
        dp = ndp;
    }
    let ans = INF;
    for (let c1 = 0; c1 < 3; c1++) {
        for (let c2 = 0; c2 < 3; c2++) {
            if (c1 !== c2 && dp[c1][c2] < ans) ans = dp[c1][c2];
        }
    }
    return ans;
};
